<template>
    <section>
        <div class="my-popups">
            <Loader :is-visible="isLoading" />
            <div class="modal d-block divUtil" style="z-index: 1050;">
                <div class="modal-dialog modal-dialog-centered modal-xl ">
                    <div class="modal-content">
                        <div
                            class="modal-header theme-primary partition-full d-flex justify-content-between align-items-center">
                            <h5 class="modal-title">{{ $t('Notes') }} {{ $t('History') }}</h5>
                            <button type="button" class="close text-white" @click="onClose">
                                <em class="fa fa-times" aria-hidden="true"></em>
                            </button>
                        </div>
                        <div class="modal-body" style="max-height: 70vh; overflow-y: auto;">
                            <div class="heading-border">
                                <h5 class="h5">
                                    <span>{{ $t('Notes') }} {{ $t('History') }}</span>
                                    <small class="float-right">
                                        <a href="javascript:;" @click="onAddNoteClick" class="mr-2"
                                            :title="$t('Add') + ' ' + $t('NOTE')">
                                            <i class="fa fa-file-text-o pr-2"></i>{{ $t('Add') }} {{ $t('New') }} {{
                                                $t('NOTE') }}
                                        </a>
                                        <a href="javascript:;" id="aListView" class="mr-2" v-show="viewMode === 'card'"
                                            @click="switchToListView" :title="$t('List') + ' ' + $t('View')">
                                            <i class="fa fa-list-ul pr-2"></i>{{ $t('List') }} {{ $t('View') }}
                                        </a>
                                        <a href="javascript:;" id="aCardView" class="mr-2" v-show="viewMode === 'list'"
                                            @click="switchToCardView" :title="$t('CARD') + ' ' + $t('View')">
                                            <i class="fa fa-th-large pr-2"></i>{{ $t('CARD') }} {{ $t('View') }}
                                        </a>
                                    </small>
                                </h5>
                            </div>
                            <!--ADD NOTES-->

                            <div class="modal-content" v-if="IsShowNotes">

                                <div class="modal-body">{{ form }}
                                    <div class="form-group" id="divNoteForm">
                                        <label>{{ $t('Note') }}<span class="mandatory">*</span></label>
                                        <ckeditor v-if="editor" :editor="editor" v-model="form.Note"
                                            :config="editorConfig"></ckeditor>
                                        <textarea v-else class="form-control" v-model="form.Note" rows="7"></textarea>
                                        <span id="spnContent" class="text-danger" v-if="contentError">
                                            {{ contentError }}
                                        </span>
                                    </div>

                                    <div class="heading-border mt-3 mb-2">
                                        <h5 class="h5">
                                            <span>{{ $t('Attachment') }}</span>
                                            <a href="javascript:;" data-toggle="popoveruserguide" :title="attachmentTooltip" data-toggle-tooltip="tooltip">
                                                <i class="fa fa-question-circle-o text-popover"
                                                    style="font-size: 14px;"></i>
                                            </a>
                                        </h5>
                                    </div>

                                    <div class="form-group">
                                        <div v-for="(fileItem, index) in fileInputs" :key="index" class="mb-2">
                                            <div class="input-group">
                                                <div class="custom-file">
                                                    <input 
                                                        type="file" 
                                                        :id="'flFileNote_' + index" 
                                                        name="FileSrc"
                                                        @change="onFileChange($event, index)"
                                                        class="form-control" 
                                                        :class="{ 'is-invalid': fileItem.error }" />
                                                    <label class="custom-file-label" :for="'flFileNote_' + index">
                                                        {{ fileItem.fileName || $t('ChooseFile') }}
                                                    </label>
                                                </div>
                                                <div class="input-group-append">
                                                    <a v-if="index === 0 && form.AttachmentId && form.AttachmentId > 0" 
                                                        :id="form.AttachmentId"
                                                        href="javascript:;" 
                                                        @click="downloadAttachment(form.AttachmentId)" 
                                                        class="round-icon-small btn-primary-light ml-2"
                                                        :title="$t('DownloadFile')">
                                                        <i class="fa fa-download"></i>
                                                    </a>
                                                    <a v-if="index === fileInputs.length - 1" 
                                                        href="javascript:;" 
                                                        @click="addFileInput" 
                                                        class="round-icon-small btn-success-light ml-2"
                                                        :title="$t('Add') + ' ' + $t('File')">
                                                        <i class="fa fa-plus"></i>
                                                    </a>
                                                    <a v-if="fileItem.file" 
                                                        href="javascript:;" 
                                                        @click="removeFileInput(index)" 
                                                        class="round-icon-small btn-danger-light ml-2"
                                                        :title="$t('Remove')">
                                                        <i class="fa fa-times"></i>
                                                    </a>
                                                    <a v-if="index === 0 && fileInputs.length > 1 && !fileItem.file && !form.AttachmentId" 
                                                        href="javascript:;" 
                                                        @click="removeFileInput(index)" 
                                                        class="round-icon-small btn-danger-light ml-2"
                                                        :title="$t('Remove')">
                                                        <i class="fa fa-refresh"></i>
                                                    </a>
                                                    <a v-if="index > 0 && !fileItem.file" 
                                                        href="javascript:;" 
                                                        @click="removeFileInput(index)" 
                                                        class="round-icon-small btn-danger-light ml-2"
                                                        :title="$t('Remove')">
                                                        <i class="fa fa-times"></i>
                                                    </a>
                                                </div>
                                            </div>
                                            <span v-if="fileItem.error" class="text-danger small d-block">
                                                {{ fileItem.error }}
                                            </span>
                                        </div>
                                        <span id="spnFile" class="text-danger" v-if="fileError">
                                            {{ fileError }}
                                        </span>
                                    </div>
                                </div>

                                <div class="modal-footer">
                                    <button class="btn btn-success" @click="onSave">
                                        <em class="fa fa-floppy-o pr-2" aria-hidden="true"></em>{{ $t('submit') }}
                                    </button>
                                    <button class="btn btn-danger" @click="onCloseNote">
                                        <em class="fa fa-times pr-2" aria-hidden="true"></em>{{ $t('Cancel') }}
                                    </button>
                                </div>
                            </div>

                            <div v-if="IsShowList">

                                <!--ADD NOTES-->

                                <!-- Add Note Form (initially hidden) -->
                                <div class="listing mt-3" v-show="showAddForm" id="divshowAddData">
                                    <slot name="add-note-form"></slot>
                                    <hr />
                                </div>

                                <!-- Card View -->
                                <div class="row card-view no-bg custom-box-width mt-3"
                                    :class="{ 'd-none': viewMode !== 'card' }" id="dvCardView">
                                    <template v-if="notes && notes.length > 0">
                                        <div class="col-md-12 col-lg-6 col-xl-6 mb-3" v-for="(note, index) in notes"
                                            :key="note.noteId">
                                            <div class="card-box blue-bg-light">
                                                <div class="card-heading" style="line-height:34px">
                                                    <span class="user-img-con mr-2">
                                                        <div class="user-image" :title="$t('ProfileImage')">
                                                            <img :src="getAvatarUrl(note.createdByAvatar)"
                                                                :alt="$t('Image')" @error="handleImageError"
                                                                loading="lazy" />
                                                        </div>
                                                    </span>
                                                    {{ note.name || '--' }}
                                                    <i v-if="index === 0" class="fa fa-star latest-note"></i>
                                                </div>
                                                <div class="card-detail-main">
                                                    <div class="card-detail">
                                                        <i class="fa fa-user" aria-hidden="true"></i>
                                                        <span>{{ note.createdBy }}</span>
                                                    </div>
                                                    <hr class="my-2" />
                                                </div>
                                                <div class="card-detail-main filterscroll" style="min-height:100px;">
                                                    <div class="cardUtilityDivisionShortDesciption mb-2 mt-2"
                                                        v-if="note.shortDesciption">
                                                        <div class="addednote-ticket-content">
                                                            <div class="col-12 p-0" :id="'lessdatacard' + (index + 1)">
                                                                <div
                                                                    class="readmorecard textelipsis_inner text-truncate">
                                                                    <div
                                                                        v-html="truncateText(note.shortDesciption, 185)">
                                                                    </div>
                                                                </div>
                                                            </div>
                                                            <div class="col-12 p-0"
                                                                :id="'showmoredatacard' + (index + 1)"
                                                                style="display:none;">
                                                                <div class="readmorecard">
                                                                    <div v-html="note.shortDesciption"></div>
                                                                </div>
                                                            </div>
                                                            <a v-if="note.shortDesciption && note.shortDesciption.length > 185"
                                                                href="javascript:;" :id="'readmorecard' + (index + 1)"
                                                                class="lessmoredesccard ancreadmoredesccard"
                                                                @click="toggleReadMoreCard(index + 1)">
                                                                {{ $t('readmore') }}
                                                            </a>
                                                            <div class="addednote-ticket-content readmoredesccard">
                                                                <a href="javascript:;"
                                                                    :id="'lessmorecard' + (index + 1)"
                                                                    class="anclessmoredesccard" style="display:none;"
                                                                    @click="toggleReadLessCard(index + 1)">
                                                                    {{ $t('Read') }} {{ $t('Less') }}
                                                                </a>
                                                            </div>
                                                        </div>
                                                    </div>
                                                </div>
                                                <div class="bottom-action">
                                                    <div class="card-date">
                                                        <i class="fa fa-calendar-o" aria-hidden="true"></i>
                                                        <span>{{ formatDate(note.createdDate) }}</span>
                                                    </div>
                                                    <div class="card-action">
                                                        <a v-if="note.canDelete" href="javascript:;"
                                                            class="round-icon-small btn-success-light updateUtilityDivisionNote"
                                                            :value="note.NoteId" @click="onEditNote(note)"
                                                            :title="$t('Edit')">
                                                            <i class="fa fa-pencil"></i>
                                                        </a>
                                                        <a v-if="note.canDelete" href="javascript:;"
                                                            class="round-icon-small btn-danger-light deleteUtilityDivisionNote"
                                                            :value="note.NoteId" @click="onDeleteNote(note)"
                                                            :title="$t('Delete')">
                                                            <i class="fa fa-trash"></i>
                                                        </a>
                                                        <a v-if="note.attachmentId && note.attachmentId > 0"
                                                            :id="note.attachmentId"
                                                            class="round-icon-small btn-primary-light downloadAttachementInZip"
                                                            :title="$t('ClickHereDownloadAttachment')"
                                                            :alt="$t('DownloadFile')" href="javascript:;"
                                                            :value="note.attachmentId"
                                                            @click="downloadAttachment(note.attachmentId)">
                                                            <i class="fa fa-download"></i>
                                                        </a>
                                                    </div>
                                                </div>
                                            </div>
                                        </div>
                                    </template>
                                    <template v-else>
                                        <div class="col-sm-12 col-md-12 col-lg-12 mt-3">
                                            <span class="text-danger text-center d-block no-record">{{
                                                $t('NoRecordfound')
                                                }}</span>
                                        </div>
                                    </template>
                                </div>

                                <!-- List View -->
                                <div class="row">
                                    <div class="col-sm-12 mt-3">
                                        <div class="card" :class="{ 'd-none': viewMode !== 'list' }" id="dvListView">
                                            <template v-if="notes && notes.length > 0">
                                                <div class="w-100" v-for="(note, index) in notes" :key="note.noteId">
                                                    <div class="card-body">
                                                        <h5 class="card-title">
                                                            {{ note.name || '--' }}
                                                            <i v-if="index === 0" class="fa fa-star latest-note"></i>
                                                            <span class="card-actions float-right">
                                                                <a v-if="note.canDelete" href="javascript:;"
                                                                    class="round-icon-small btn-success-light updateUtilityDivisionNote"
                                                                    :value="note.noteId" @click="onEditNote(note)"
                                                                    :title="$t('Edit')">
                                                                    <em class="fa fa-pencil"></em>
                                                                </a>
                                                                <a v-if="note.canDelete" href="javascript:;"
                                                                    class="round-icon-small btn-danger-light deleteUtilityDivisionNote"
                                                                    :value="note.noteId" @click="onDeleteNote(note)"
                                                                    :title="$t('Delete')">
                                                                    <em class="fa fa-trash"></em>
                                                                </a>
                                                                <a v-if="note.attachmentId && note.attachmentId > 0"
                                                                    :id="note.attachmentId"
                                                                    class="round-icon-small btn-primary-light downloadAttachementInZip"
                                                                    :title="$t('ClickHereDownloadAttachment')"
                                                                    :alt="$t('DownloadFile')" href="javascript:;"
                                                                    :value="note.attachmentId"
                                                                    @click="downloadAttachment(note.attachmentId)">
                                                                    <em class="fa fa-download"></em>
                                                                </a>
                                                            </span>
                                                        </h5>
                                                        <div class="card-text mb-2">
                                                            <div class="utilityDivisionShortDesciption mb-2 mt-2"
                                                                v-if="note.shortDescription">
                                                                <div class="addednote-content filterscroll"
                                                                    style="max-height:100px; overflow-y: auto;">
                                                                    <div class="col-12 p-0"
                                                                        :id="'lessdata' + (index + 1)">
                                                                        <div
                                                                            class="readmore textelipsis_inner text-truncate">
                                                                            <div
                                                                                v-html="truncateText(note.shortDescription, 185)">
                                                                            </div>
                                                                        </div>
                                                                    </div>
                                                                    <div class="col-12 p-0"
                                                                        :id="'showmoredata' + (index + 1)"
                                                                        style="display:none;">
                                                                        <div class="readmore">
                                                                            <div v-html="note.shortDescription"></div>
                                                                        </div>
                                                                    </div>
                                                                    <a v-if="note.shortDescription && note.shortDescription.length > 185"
                                                                        href="javascript:;"
                                                                        :id="'readmore' + (index + 1)"
                                                                        class="lessmoredesc ancreadmoredesc"
                                                                        @click="toggleReadMore(index + 1)">
                                                                        {{ $t('readmore') }}
                                                                    </a>
                                                                    <div class="addednote-ticket-content readmoredesc">
                                                                        <a href="javascript:;"
                                                                            :id="'lessmore' + (index + 1)"
                                                                            class="anclessmoredesc"
                                                                            style="display:none;"
                                                                            @click="toggleReadLess(index + 1)">
                                                                            {{ $t('Read') }} {{ $t('Less') }}
                                                                        </a>
                                                                    </div>
                                                                </div>
                                                            </div>
                                                        </div>
                                                        <p class="card-text Userndate">
                                                            <i class="fa fa-user"></i>
                                                            {{ note.createdBy }}
                                                            <span class="created-date">{{ formatDate(note.createdDate)
                                                                }}</span>
                                                        </p>
                                                    </div>
                                                </div>
                                            </template>
                                            <template v-else>
                                                <div class="col-sm-12 col-md-12 col-lg-12 mt-3">
                                                    <span class="text-danger text-center d-block no-record">{{
                                                        $t('NoRecordfound') }}</span>
                                                </div>
                                            </template>
                                        </div>
                                    </div>
                                </div>

                            </div>
                        </div>
                        <!-- <div class="modal-footer">
                            <button class="btn btn-danger" @click="onClose">
                                <em class="fa fa-close pr-2" aria-hidden="true"></em>{{ $t('Close') }}
                            </button>
                        </div> -->
                    </div>
                </div>
            </div>
        </div>
    </section>
</template>

<script>
import { locateBillingService } from '../../../services/locateBillingService';
import DataServices from '../../../services/DataService';
import Loader from '../../../components/Common/Loader.vue';
import http from '../../../http-common';
import { useloggedUserInfo } from '../../../stores/UserInfo';

export default {
    components: {
        Loader
    },
    name: 'PartialNotesList',
    computed: {
        CLASSIC_EDITOR() {
            debugger
            const userStore = useloggedUserInfo();
            return userStore.CLASSIC_EDITOR;
        },
    attachmentTooltip() {
        if (!this.AllowedPerFileSizeInMb || !this.AllowedFileTypes) return '';
         return `
            Maximum upload size per file: ${this.AllowedPerFileSizeInMb} MB
            Allowed File Types: ${this.AllowedFileTypes}`.trim();
        }
    },
    watch: {
        noteId: {
            immediate: false, // set true if you want it to run on first load also
            handler(newVal, oldVal) {
                if (newVal && newVal > 0) {
                    this.loadNote();
                }
            }
        }
    },
    props: {
        divisionId: {
            type: [Number, String],
            default: null
        },
        utilityId: {
            type: [Number, String],
            default: null
        },
        clientId: {
            type: [Number, String],
            default: null
        },
        uniqueName: {
            type: String,
            default: ''
        },
        noteId: {
            type: [Number, String],
            default: null
        },
    },
    data() {
        var vm = this;
        return {
            isLoading: false,
            notes: [],
            viewMode: 'list', // 'list' or 'card'
            showAddForm: false,



            form: {
                NoteId: vm.noteId,
                UtilityId: vm.utilityId,
                DivisionId: vm.divisionId,
                ClientId: vm.clientId,
                UniqueName: vm.uniqueName,
                Note: '',
                Privacy: 'Public',
                AttachmentId: null
            },
            fileInputs: [
                {
                    file: null,
                    fileName: '',
                    error: ''
                }
            ],
            contentError: '',
            fileError: '',
            editor: null,
            editorConfig: {
                toolbar: [
                    'Bold', 'Italic', 'Underline',
                    '|',
                    'JustifyLeft', 'JustifyCenter', 'JustifyRight', 'JustifyBlock'
                ],
                height: 200
            },
            IsShowNotes: false,
            IsShowList: true,
            AllowedFileTypes:'',
            AllowedPerFileSizeInMb:0
        };
    },
    created() {
        debugger
        var vm = this;
        this.loadNotesList();

        try {
            const userStore = useloggedUserInfo();
            if (userStore.CLASSIC_EDITOR) {
                vm.editor = userStore.CLASSIC_EDITOR;
            } else {
                // Use imported ClassicEditor and store it
                vm.editor = ClassicEditor;
                userStore.setClassicEditor(ClassicEditor);
            }
        } catch (e) {
            console.warn('Could not get CLASSIC_EDITOR from store:', e);
            vm.editor = ClassicEditor;
        }

        // Load note data if editing
        if (vm.noteId && vm.noteId > 0) {
            vm.loadNote();
        }
         vm.GetAllowFileType();
    },
    methods: {
        async loadNotesList() {
            var vm = this;
            vm.isLoading = true;
            try {
                var params = [];
                if (vm.divisionId) params.push(`divisionId=${vm.divisionId}`);
                if (vm.utilityId) params.push(`utilityId=${vm.utilityId}`);
                if (vm.clientId) params.push(`clientId=${vm.clientId}`);

                var url = params.join('&');
                var response = await locateBillingService.GetNoteList(url);
                if (response && response.data) {
                    
                    vm.notes = response.data;
                } else {
                    vm.notes = [];
                }
            } catch (error) {
                console.log('Error loading notes:', error);
                vm.notes = [];
            } finally {
                vm.isLoading = false;
            }
        },
        formatDate(value) {
            if (!value) return '';
            var d = new Date(value);
            if (isNaN(d.getTime())) return value;
            return d.toLocaleString();
        },
        truncateText(text, maxLength) {
            if (!text || text.length <= maxLength) return text;
            return text.substring(0, maxLength) + '...';
        },
        getAvatarUrl(avatar) {
            if (!avatar) {
                return '/Content/images/DefaultImages/avatar-icon.jpg';
            }
            // You may need to adjust this based on your image helper
            return avatar;
        },
        handleImageError(event) {
            event.target.src = '/Content/images/DefaultImages/avatar-icon.jpg';
        },
        toggleReadMore(index) {
            var lessData = document.getElementById('lessdata' + index);
            var showMoreData = document.getElementById('showmoredata' + index);
            var readMore = document.getElementById('readmore' + index);
            var lessMore = document.getElementById('lessmore' + index);

            if (lessData && showMoreData && readMore && lessMore) {
                lessData.style.display = 'none';
                readMore.style.display = 'none';
                showMoreData.style.display = 'block';
                lessMore.style.display = 'block';
            }
        },
        toggleReadLess(index) {
            var lessData = document.getElementById('lessdata' + index);
            var showMoreData = document.getElementById('showmoredata' + index);
            var readMore = document.getElementById('readmore' + index);
            var lessMore = document.getElementById('lessmore' + index);

            if (lessData && showMoreData && readMore && lessMore) {
                showMoreData.style.display = 'none';
                lessMore.style.display = 'none';
                lessData.style.display = 'block';
                readMore.style.display = 'block';
            }
        },
        toggleReadMoreCard(index) {
            var lessData = document.getElementById('lessdatacard' + index);
            var showMoreData = document.getElementById('showmoredatacard' + index);
            var readMore = document.getElementById('readmorecard' + index);
            var lessMore = document.getElementById('lessmorecard' + index);

            if (lessData && showMoreData && readMore && lessMore) {
                lessData.style.display = 'none';
                readMore.style.display = 'none';
                showMoreData.style.display = 'block';
                lessMore.style.display = 'block';
            }
        },
        toggleReadLessCard(index) {
            var lessData = document.getElementById('lessdatacard' + index);
            var showMoreData = document.getElementById('showmoredatacard' + index);
            var readMore = document.getElementById('readmorecard' + index);
            var lessMore = document.getElementById('lessmorecard' + index);

            if (lessData && showMoreData && readMore && lessMore) {
                showMoreData.style.display = 'none';
                lessMore.style.display = 'none';
                lessData.style.display = 'block';
                readMore.style.display = 'block';
            }
        },
        switchToListView() {
            this.viewMode = 'list';
        },
        switchToCardView() {
            this.viewMode = 'card';
        },
        onAddNoteClick() {
            debugger
            this.$emit('add-note');
            this.showAddForm = !this.showAddForm;
            this.IsShowNotes = true;
            // Reset note content when adding a new note
            this.form.Note = null;
            // Reset attachment inputs and errors
            this.fileInputs = [{
                file: null,
                fileName: '',
                error: ''
            }];
            this.fileError = '';
        },
        onEditNote(note) {
            debugger
            this.$emit('edit-note', note);
            this.IsShowNotes = true;
            this.IsShowList = false;
        },
        onDeleteNote(note) {
            var vm = this;
            var confirmMessage = vm.$t('ConfirmDelete');
            var confirmTitle = vm.$t('DeleteNote');

            vm.confirmR(confirmMessage, true, confirmTitle, function () {
                vm.isLoading = true;
                locateBillingService.DeleteNote({
                    Id: note.noteId,
                    UtilityId: note.utilityId,
                    DivisionId: note.divisionId,
                    ClientId: note.clientId,
                    TicketPrivacy: note.privacy,
                    UniqueName: vm.uniqueName
                }).then(function (response) {
                    if (response && response.data) {
                        if (response.data.status === 'Success' || response.data.code === '0') {
                            vm.ShowAlert(response.data.msg || vm.$t('DeletedSuccessfully'), "success", vm.$t('Alert'));
                            vm.loadNotesList();
                            vm.$emit('note-deleted', response.data.result);
                        } else {
                            vm.ShowAlert(response.data.msg || vm.$t('ErrorWhileProcessingRequest'), "failure", vm.$t('Alert'));
                        }
                    }
                    vm.isLoading = false;
                }).catch(function (error) {
                    console.log('Error deleting note:', error);
                    vm.ShowAlert(vm.$t('ErrorWhileProcessingRequest'), "failure", vm.$t('Alert'));
                    vm.isLoading = false;
                });
            });
        },
        downloadAttachment(attachmentId) {
            debugger
            var vm = this;
            try {
                if (!attachmentId) {
                    return;
                }

                vm.isLoading = true;

                // Use axios with blob response type to download file without redirecting
                http.instance.get('/Client/DownloadAttachments', {
                    params: { fileId: attachmentId },
                    responseType: 'blob' // Important: tells axios to handle response as binary data
                }).then(function (response) {
                    // Create a blob from the response data
                    var blob = new Blob([response.data], { type: 'application/zip' });

                    // Create a temporary URL for the blob
                    var url = window.URL.createObjectURL(blob);

                    // Create a temporary anchor element and trigger download
                    var link = document.createElement('a');
                    link.href = url;
                    link.download = 'attachment_' + attachmentId + '.zip'; // Set filename
                    link.style.display = 'none';

                    // Append to body, click, then remove
                    document.body.appendChild(link);
                    link.click();
                    document.body.removeChild(link);

                    // Clean up the temporary URL
                    window.URL.revokeObjectURL(url);

                    vm.isLoading = false;
                }).catch(function (error) {
                    console.error('Error downloading attachment:', error);
                    vm.isLoading = false;

                    // Check if error response has a message
                    if (error.response && error.response.data) {
                        // Try to read error message from blob if it's an error response
                        if (error.response.data instanceof Blob) {
                            var reader = new FileReader();
                            reader.onload = function () {
                                try {
                                    var errorData = JSON.parse(reader.result);
                                    vm.ShowAlert(errorData.message || vm.$t('ErrorWhileProcessingRequest'), "failure", vm.$t('Alert'));
                                } catch (e) {
                                    vm.ShowAlert(vm.$t('ErrorWhileProcessingRequest'), "failure", vm.$t('Alert'));
                                }
                            };
                            reader.readAsText(error.response.data);
                        } else {
                            vm.ShowAlert(error.response.data.message || vm.$t('ErrorWhileProcessingRequest'), "failure", vm.$t('Alert'));
                        }
                    } else {
                        vm.ShowAlert(vm.$t('ErrorWhileProcessingRequest'), "failure", vm.$t('Alert'));
                    }
                });
            } catch (ex) {
                console.error('Error downloading attachment:', ex);
                vm.isLoading = false;
                vm.ShowAlert(vm.$t('ErrorWhileProcessingRequest'), "failure", vm.$t('Alert'));
            }
        },
        onCloseNote() {
            this.IsShowNotes = false;
            this.IsShowList = true;
            this.fileInputs = [{
                file: null,
                fileName: '',
                error: ''
            }];
            this.fileError = '';
            //this.$emit('close');
        },
        onClose() {
            debugger
            //this.IsShowNotes = false;
            this.$emit('close');
        },



        async loadNote() {
            var vm = this;
            vm.isLoading = true;
            try {
                var params = `noteId=${vm.noteId}`;
                if (vm.utilityId) params += `&utilityId=`;
                if (vm.divisionId) params += `&divisionId=${vm.divisionId}`;
                if (vm.clientId) params += `&clientId=${vm.clientId}`;

                var response = await locateBillingService.GetNoteById(params);
                if (response && response.data) {
                    vm.form.Note = response.data.Note || response.data.note || '';
                    vm.form.Privacy = response.data.Privacy || response.data.privacy || 'Public';
                    vm.form.AttachmentId = response.data.AttachmentId || response.data.attachmentId || null;
                    vm.fileInputs = [{
                        file: null,
                        fileName: response.data.fileName || response.data.FileName || '',
                        error: ''
                    }];
                    if (response.data.filePath && response.data.attachmentMime) {
                        var fileFromServer = await vm.createFileFromServer(response.data);
                        vm.fileInputs[0].file = fileFromServer;
                        vm.fileInputs[0].fileName = response.data.fileName || response.data.FileName || '';
                    }
                }
            } catch (error) {
                console.log('Error loading note:', error);
            } finally {
                vm.isLoading = false;
            }
        },
        async createFileFromServer(responseData) {
            const fileUrl = `/${responseData.filePath}`;
            const res = await fetch(fileUrl);
            const blob = await res.blob();

            const mimeInfo = JSON.parse(responseData.attachmentMime);

            return new File(
                [blob],
                responseData.fileName || "attachment." + mimeInfo.Extension,
                {
                    type: mimeInfo.ContentType,
                    lastModified: Date.now()
                }
            );
        },
        validateNote() {
            var vm = this;
            // Get content from CKEditor (strip HTML tags and &nbsp;)
            var content = (vm.form.Note || '').replace(/&nbsp;/gi, '');
            content = content.split('<p>').join('');
            content = content.split('</p>').join('');
            content = content.split('</br>').join('');
            content = content.replace(/<[^>]*>?/gm, '').trim();

            if (!content || content === '') {
                vm.contentError = vm.$t('NoteDescRequired') || vm.$t('Required');
                if (document.getElementById('spnContent')) {
                    document.getElementById('spnContent').classList.remove('valid-feedback', 'hidden');
                    document.getElementById('spnContent').classList.add('text-danger');
                }
                return false;
            }
            if (content.length > 5000) {
                vm.contentError = vm.$t('DescLessThen')
                    ? vm.$t('DescLessThen').replace('{0}', vm.$t('Description')).replace('{1}', '5000')
                    : vm.$t('Required');
                if (document.getElementById('spnContent')) {
                    document.getElementById('spnContent').classList.remove('valid-feedback', 'hidden');
                    document.getElementById('spnContent').classList.add('text-danger');
                }
                return false;
            }
            vm.contentError = '';
            if (document.getElementById('spnContent')) {
                document.getElementById('spnContent').classList.remove('text-danger');
                document.getElementById('spnContent').classList.add('valid-feedback');
                document.getElementById('spnContent').innerHTML = '';
            }
            return true;
        },
        onFileChange(e, index) {
            debugger
            var vm = this;
            vm.fileError = '';
            const file = e.target.files[0];
            const fileInput = vm.fileInputs[index];
            
            if (!file) {
                fileInput.file = null;
                fileInput.fileName = '';
                fileInput.error = '';
                return;
            }

            // Validate file name
            const fname = file.name.split('.')[0];
            const re = new RegExp('^[^<>%$#%;:!,|]*$');
            if (!re.test(fname)) {
                fileInput.error = vm.$t('FileNameShouldNotContainSpecialCharacters') || 'File Name should not contain special characters';
                e.target.value = '';
                fileInput.file = null;
                fileInput.fileName = '';
                return;
            }

            // Validate file size if AllowedPerFileSizeInMb is set
            if (vm.AllowedPerFileSizeInMb && vm.AllowedPerFileSizeInMb > 0) {
                const fileSizeInMb = file.size / (1024 * 1024);
                if (fileSizeInMb > vm.AllowedPerFileSizeInMb) {
                    fileInput.error = `File exceeds maximum size of ${vm.AllowedPerFileSizeInMb} MB`;
                    e.target.value = '';
                    fileInput.file = null;
                    fileInput.fileName = '';
                    return;
                }
            }

            // Validate file type if AllowedFileTypes is set
            if (vm.AllowedFileTypes) {
                const fileExtension = '.' + file.name.split('.').pop().toLowerCase();
                const allowedTypes = vm.AllowedFileTypes.split(',').map(t => t.trim().toLowerCase());
                if (!allowedTypes.some(type => fileExtension === type.toLowerCase())) {
                    fileInput.error = `File type not allowed. Allowed types: ${vm.AllowedFileTypes}`;
                    e.target.value = '';
                    fileInput.file = null;
                    fileInput.fileName = '';
                    return;
                }
            }

            // File is valid - store it
            fileInput.file = file;
            fileInput.fileName = file.name;
            fileInput.error = '';
            
            console.log('File selected at index', index, ':', file.name);
            console.log('Total files in fileInputs:', vm.fileInputs.filter(f => f.file).length);
        },
        addFileInput() {
            this.fileInputs.push({
                file: null,
                fileName: '',
                error: ''
            });
        },
        removeFileInput(index) {
            if (this.fileInputs.length > 1) {
                this.fileInputs.splice(index, 1);
            } else {
                // If only one input, just clear it
                this.fileInputs[0].file = null;
                this.fileInputs[0].fileName = '';
                this.fileInputs[0].error = '';
                const fileInput = document.getElementById('flFileNote_0');
                if (fileInput) {
                    fileInput.value = '';
                }
            }
            this.fileError = '';
        },
        async onSave() {
            debugger
            var vm = this;
            if (!vm.validateNote()) {
                return;
            }
            vm.isLoading = true;
            try {
                var formData = new FormData();
                formData.append('NoteId', vm.form.NoteId || '');
                formData.append('Note', vm.form.Note || '');
                formData.append('UtilityId', vm.form.UtilityId || '');
                formData.append('DivisionId', vm.form.DivisionId || '');
                formData.append('ClientId', vm.form.ClientId || '');
                formData.append('Privacy', vm.form.Privacy || 'Public');
                formData.append('UniqueName', vm.form.UniqueName || '');

                // Collect all files from fileInputs
                var fileCount = 0;
                var filesToSend = [];
                
                for (var i = 0; i < vm.fileInputs.length; i++) {
                    var fileObj = vm.fileInputs[i].file;
                    if (fileObj && fileObj instanceof File) {
                        filesToSend.push(fileObj);
                        fileCount++;
                        console.log('File found at index', i, ':', fileObj.name, 'Size:', fileObj.size);
                    } else if (fileObj) {
                        console.warn('Invalid file object at index', i, ':', typeof fileObj);
                    }
                }

                // Append all files to FormData with the same name 'FileSrc'
                // This ensures they all appear in Request.Form.Files on the server
                for (var j = 0; j < filesToSend.length; j++) {
                    formData.append('FileSrc', filesToSend[j]);
                }

                console.log('Total files to send:', fileCount);
                if (fileCount === 0) {
                    console.warn('No files to send!');
                }
                
                // Debug: Log all FormData entries
                console.log('FormData entries:');
                for (var pair of formData.entries()) {
                    if (pair[1] instanceof File) {
                        console.log(pair[0] + ': [File] ' + pair[1].name + ' (' + pair[1].size + ' bytes)');
                    } else {
                        console.log(pair[0] + ': ' + pair[1]);
                    }
                }

                var response = await locateBillingService.AddNoteUtilityDivision(formData);
                if (response && response.data) {
                    // MVC returns: Status (0=success, 1=failure), UtilityId, DivisionId, ClientId, TotalNotes, msg
                    if (response.data.Status === 0 || response.data.status === 0) {
                        vm.ShowAlert(response.data.msg || response.data.Msg || vm.$t('SavedSuccessfully'), "success", vm.$t('Alert'));
                        debugger
                        // vm.$emit('saved', {
                        //     Status: response.data.Status || response.data.status,
                        //     UtilityId: response.data.UtilityId || response.data.utilityId,
                        //     DivisionId: response.data.DivisionId || response.data.divisionId,
                        //     ClientId: response.data.ClientId || response.data.clientId,
                        //     TotalNotes: response.data.TotalNotes || response.data.totalNotes || 0,
                        //     msg: response.data.msg || response.data.Msg,
                        //     UniqueName: vm.form.UniqueName,
                        //     LatestNote: response.data.msg || response.data.Msg
                        // });
                        vm.fileInputs = [{
                            file: null,
                            fileName: '',
                            error: ''
                        }];
                        vm.onClose();
                        vm.$parent.OnUpdateNotesCount();
                    } else {
                        vm.ShowAlert(response.data.msg || response.data.Msg || vm.$t('ErrorWhileProcessingRequest'), "failure", vm.$t('Alert'));
                    }
                } else {
                    vm.ShowAlert(vm.$t('ErrorWhileProcessingRequest'), "failure", vm.$t('Alert'));
                }
            } catch (error) {
                console.log('Error saving note:', error);
                vm.ShowAlert(vm.$t('ErrorWhileProcessingRequest'), "failure", vm.$t('Alert'));
            } finally {
                vm.isLoading = false;
            }
        },
        async GetAllowFileType() {
            debugger;
            try {
                const response =  await DataServices.AllowFileType();
                this.AllowedFileTypes = response?.data?.AllowedFileTypes;
                this.AllowedPerFileSizeInMb = response?.data?.AllowedPerFileSizeInMb;      

                
            } catch (err) {
                    console.error("GetAllowFileType failed", err);
            }
        },
        // downloadAttachment(attachmentId) {
        //     var vm = this;
        //     if (attachmentId) {
        //         var url = `/Client/DownloadAttachments?fileId=${attachmentId}`;
        //         window.open(url, '_blank');
        //     }
        // }

    }
};
